/**
 * EXPERIMENTAL - transport used by thread realtime.
 */
export type ThreadRealtimeStartTransport = {
    "type": "websocket";
} | {
    "type": "webrtc";
    /**
     * SDP offer generated by a WebRTC RTCPeerConnection after configuring audio and the
     * realtime events data channel.
     */
    sdp: string;
};
